#include<bits/stdc++.h>
using namespace std;
string  s[101],sss;
int l[101],n,maxx;
bool cha(string x,string y,int k){
	int lenx=x.length();
	for(int i=0;i<k;i++){
		if(x[lenx-k+i]!=y[i]){
			return false;
		}
	}return true;
}
void cp(string &x,string y,int k){
	int leny=y.length();
	for(int i=k;i<leny;i++){
		x+=y[i];
	}
}
void str(string ss){
	int w=ss.length();
	maxx=max(maxx,w);
	for(int i=1;i<=n;i++){
		if(l[i]>=2) continue;
		for(int j=1;j<=s[i].length();j++){
			if(cha(ss,s[i],j)){
				string t=ss;
				cp(t,s[i],j);
				if(t==ss) continue;
				l[i]++;
				str(t);
				l[i]--;
			}
		}
	}
}
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>s[i];
	}
	cin>>sss;
	str(sss);
	cout<<maxx;
	return 0;
}
